describe('EventBus subscription', () => {
  it('should handle order:created events from EventBus', async () => {
    const eventBus = new EventBus();
    service.subscribeToEvents(eventBus);

    await eventBus.emit({
      type: 'order:created',
      order: testOrder,
      user: testUser,
      timestamp: new Date(),
    });

    const notifications = service.getNotifications();
    expect(notifications).toHaveLength(1);
    expect(notifications[0]?.subject).toContain('Order Confirmation');
  });

  it('should handle order:status-changed events from EventBus', async () => {
    const eventBus = new EventBus();
    service.subscribeToEvents(eventBus);

    const confirmedOrder: Order = { ...testOrder, status: 'confirmed' };
    await eventBus.emit({
      type: 'order:status-changed',
      order: confirmedOrder,
      previousStatus: 'pending',
      newStatus: 'confirmed',
      timestamp: new Date(),
    });

    const notifications = service.getNotifications();
    expect(notifications).toHaveLength(1);
    expect(notifications[0]?.subject).toContain('Order Update');
    expect(notifications[0]?.body).toContain('pending');
    expect(notifications[0]?.body).toContain('confirmed');
  });

  it('should handle both event types in sequence', async () => {
    const eventBus = new EventBus();
    service.subscribeToEvents(eventBus);

    await eventBus.emit({
      type: 'order:created',
      order: testOrder,
      user: testUser,
      timestamp: new Date(),
    });

    const confirmedOrder: Order = { ...testOrder, status: 'confirmed' };
    await eventBus.emit({
      type: 'order:status-changed',
      order: confirmedOrder,
      previousStatus: 'pending',
      newStatus: 'confirmed',
      timestamp: new Date(),
    });

    const notifications = service.getNotifications();
    expect(notifications).toHaveLength(2);
    expect(notifications[0]?.subject).toContain('Order Confirmation');
    expect(notifications[1]?.subject).toContain('Order Update');
  });
});

describe('utility methods', () => {
  it('should return copies from getNotifications', () => {
    service.notifyOrderCreated(testOrder, testUser);

    const first = service.getNotifications();
    const second = service.getNotifications();
    expect(first).not.toBe(second);
    expect(first).toEqual(second);
  });
});

